mapper.select:
select t1.write_year ,t1.doc_type ,t1.doc_no ,t1.comp_id ,t1.part_comp_id ,part_comp_nm , t1.desc , t1.part_comp_item , t1.zip_cd , t1.addrs1 , t1.addrs2 , t1.exam_dt , t1.use_yn , t1.created_at , t1.created_by , t1.updated_at , t1.updated_by , t2.part_comp_item_nm as partCompItemNm
, t3.signature as investigator1Sign , t4.signature as investigator2Sign
, t3.hr_nm as investigator1Nm , t4.hr_nm as investigator2Nm , case when t3.hr_id is not null and t3.signature is not null and t4.hr_id is null and t4.signature is null then 'Y' when t3.hr_id is not null and t3.signature is not null and t4.hr_id is not null and t4.signature is null then 'I' when t3.hr_id is not null and t3.signature is not null and t4.hr_id is not null and t4.signature is not null then 'Y' when t3.hr_id is not null and t3.signature is null and t4.hr_id is null and t4.signature is null then 'C' when t3.hr_id is not null and t3.signature is null and t4.hr_id is not null and t4.signature is not null then 'I' when t3.hr_id is null and t3.signature is null and t4.hr_id is not null and t4.signature is null then 'C' when t3.hr_id is null and t3.signature is null and t4.hr_id is not null and t4.signature is not null then 'Y' when t3.hr_id is null and t3.signature is null and t4.hr_id is null and t4.signature is null then 'C' end as approvalStatus , t1.reg_dt from esg.tb_contractor_investigation_form t1 left join esg.tb_partner_comp_item t2 on t1.comp_id = t2.comp_id and t1.part_comp_item = t2.part_comp_item_id left join esg.tb_approval_info t3 on t3.target_type = 'CIF' and t3.target_id = t1.write_year || t1.doc_no and t3.type = 'investigator1' left join esg.tb_approval_info t4 on t4.target_type = 'CIF' and t4.target_id = t1.write_year || t1.doc_no and t4.type = 'investigator2' where t1.comp_id = #{compId} and t1.write_year = #{writeYear}
and t1.doc_type = #{docType} and t1.doc_no = #{docNo}
order by t1.use_yn desc, t1.created_at desc

select t1.*
     , row_number() over(order by t1.doc_seq asc) as ordSeq
from esg.tb_contractor_investigation_form_detail t1
where t1.comp_id = #{compId}
  and t1.write_year = #{writeYear}
  and t1.doc_type = #{docType}
  and t1.doc_no = #{docNo}
order by t1.doc_seq asc

mapper.update:
UPDATE esg.tb_contractor_investigation_form
   SET part_comp_id = #{partCompId}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}
   AND comp_id = #{compId}

UPDATE esg.tb_contractor_investigation_form
   SET use_yn = 'N',
       updated_at = now(),
       updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}
   AND comp_id = #{compId}

