UPDATE esg.tb_dataset_contractor_checklist SET
                                               inspection_nm = #{inspectionNm},
                                               use_yn = #{useYn},
                                               ord_seq = #{ordSeq},
                                               updated_at = now(),
                                               updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND inspection_id= #{inspectionId};

UPDATE esg.tb_dataset_contractor_checklist_detail
   SET inspection_item_nm = #{inspectionItemNm},
       upper_score = #{upperScore},
       middle_score = #{middleScore},
       lower_score = #{lowerScore},
       use_yn = #{useYn},
       ord_seq = #{ordSeq},
       updated_at = now(),
       updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND inspection_id = #{inspectionId}
  AND inspection_item_id = #{inspectionItemId}

UPDATE esg.tb_dataset_contractor_checklist
   SET use_yn = 'N'
     , updated_at = NOW()
     , updated_by = #{updatedBy}
 WHERE comp_id = #{compId}
   AND inspection_id = #{inspectionId}

UPDATE esg.tb_dataset_contractor_checklist_detail
   SET use_yn = 'N'
     , updated_at = NOW()
     , updated_by = #{updatedBy}
 WHERE comp_id = #{compId}
   AND inspection_id = #{inspectionId}
   AND inspection_item_id = #{inspectionItemId}
